&lt;li&gt;&lt;em&gt;Guardian&lt;/em&gt; (&lt;a href=&quot;https://www.theguardian.com/us-news/2025/feb/27/barnard-palestine-protest&quot; class=&quot;external&quot;&gt;link&lt;svg aria-hidden=&quot;true&quot; class=&quot;external-icon&quot; style=&quot;max-width:0.8em;max-height:0.8em&quot; viewBox=&quot;0 0 512 512&quot;&gt;&lt;path d=&quot;M320 0H288V64h32 82.7L201.4 265.4 178.7 288 224 333.3l22.6-22.6L448 109.3V192v32h64V192 32 0H480 320zM32 32H0V64 480v32H32 456h32V480 352 320H424v32 96H64V96h96 32V32H160 32z&quot;&gt;&lt;/path&gt;&lt;/svg&gt;&lt;/a&gt;)&lt;/li&gt;
